oxy_webhelp_navlinks = {"aws_s3_recovery-d30753e15817":{"topics":[{"title":"Recovery options for Amazon S3","shortdesc":"<p class=\"shortdesc\">A comparative overview of the various recovery options for Amazon S3 buckets or its         objects.<\/p>","href":"amazon_S3\/s3_recovery_options.html","attributes":{"data-id":"s3_recovery_options"},"menu":{"hasChildren":false},"tocID":"s3_recovery_options-d30753e15831","topics":[]},{"title":"Prioritized recovery for Amazon S3","shortdesc":"<p class=\"shortdesc\">You can prioritize the recovery of specific Amazon S3 objects using glob patterns to         recover your most critical data first. You can also use glob patterns to selectively recover         specific objects from your Amazon S3.<\/p>","href":"saas\/pattern_based_recovery.html","attributes":{"data-id":"pattern_based_recovery"},"menu":{"hasChildren":false},"tocID":"pattern_based_recovery-d30753e15842","topics":[]},{"title":"Recover Amazon S3 buckets","shortdesc":"<p class=\"shortdesc\">You can recover your data from a snapshot of an Amazon S3 bucket by using an         on-demand or policy-based snapshots. You can take an on-demand snapshot when needed and a         policy-based snapshot depending on the policies associated with the SLA Domain assigned to         the S3 bucket.<\/p>","href":"amazon_S3\/recovery_amazon_s3_snapshots.html","attributes":{"data-id":"recovery_amazon_s3_snapshots"},"menu":{"hasChildren":false},"tocID":"recovery_amazon_s3_snapshots-d30753e15853","next":"recovery_amazon_s3_snapshots-d30753e15853"},{"title":"Recovery report for Amazon S3 buckets","shortdesc":"<p class=\"shortdesc\">If the Amazon S3 bucket backup process fails because of technical issues, you can         download a report with a list of objects that could not be completely recovered and use the         report for troubleshooting.<\/p>","href":"amazon_S3\/recovery_report_for_amazon_s3_buckets.html","attributes":{"data-id":"recovery_report_for_amazon_s3_buckets"},"menu":{"hasChildren":false},"tocID":"recovery_report_for_amazon_s3_buckets-d30753e15897","next":"recovery_report_for_amazon_s3_buckets-d30753e15897"}]}};